const comment_account = $('Route Post or Comment').all()[0].json;

const extractedIP = $('Get Proxy Exit IP').first().json.origin
const profile_id=$('Open Multilogin Profile').first().json.data.id

// Extract fields safely from broken AI JSON
const x=$input.first().json.output
const usernameMatch = x.match(/"username"\s*:\s*"([^"]+)/);
const username = usernameMatch ? usernameMatch[1] : null;

const commentMatch = x.match(/"comment_content"\s*:\s*"([^"]+)/);
const comment_content = commentMatch ? commentMatch[1] : null;


const comment_postMatch = x.match(/"comment_post"\s*:\s*"([^"]+)/);
const posts_links = comment_postMatch ? comment_postMatch[1] : null;

const comment_permalingMatch = x.match(/"coments_Permalink"\s*:\s*"([^"]+)/);
const comments_links = comment_permalingMatch ? comment_permalingMatch[1] : null;

const postKarmaMatch = x.match(/"post_karma"\s*:\s*(\d+)/);
const post_karma = postKarmaMatch ? Number(postKarmaMatch[1]) : 0;

const commentKarmaMatch = x.match(/"comment_karma"\s*:\s*(\d+)/);
const comment_karma = commentKarmaMatch ? Number(commentKarmaMatch[1]) : 0;

const totalKarmaMatch = x.match(/"total_karma"\s*:\s*(\d+)/);
const total_karma = totalKarmaMatch ? Number(totalKarmaMatch[1]) : 0;

const statusMatch = x.match(/"status"\s*:\s*"([^"]+)/);
const status = statusMatch ? statusMatch[1] : "comment_failed";
comment_account.last_allocated_ip=extractedIP
// Build final object
return [{
  json: {
    ...comment_account,
    username,
    posts_links,
    comment_content,
    comments_links,
    post_karma,
    comment_karma,
    total_karma,
    last_action_status: status === "comment_success" ? "comment_success" : "comment_failed",
    profile_id,
    comments_made_today: Number(comment_account.comments_made_today || 0) + (status === "comment_success" ? 1 : 0),
    time_of_comment: new Date().toISOString()
  }
}];

const accounts = $input.all().map(i => i.json);
const result = [];

const now = new Date();
const currentHour = now.getHours();

// ---- ACTIVE HOURS 0 → 12 ----
if (currentHour >= 12) {
    return [{
        json: {
            action: "none",
            wait_minutes: 5
        }
    }];
}

// ---- RANDOM ----
function randomBetween(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
}

// shuffle accounts
accounts.sort(() => Math.random() - 0.5);

// pick random accounts
const activeAccounts = accounts.slice(0, randomBetween(3, 8));

for (const acc of activeAccounts) {

    const lastPostTime = acc.time_of_post ? new Date(acc.time_of_post) : null;
    const lastCommentTime = acc.time_of_comment ? new Date(acc.time_of_comment) : null;

    const postDelay = randomBetween(60,180) * 60 * 1000;      // 1–3 hours
    const commentDelay = randomBetween(30,120) * 60 * 1000;   // 30–120 min

    const actionType = Math.random() < 0.5 ? "post" : "comment";

    // ---- POST CHECK ----
    if (
        actionType === "post" &&
        (!lastPostTime || (now - lastPostTime) >= postDelay)
    ) {

        result.push({
            json: {
                ...acc,
                action: "post",
                wait_minutes: 5,
                scheduled_hour: currentHour
            }
        });

    }

    // ---- COMMENT CHECK ----
    if (
        actionType === "comment" &&
        (!lastCommentTime || (now - lastCommentTime) >= commentDelay)
    ) {

        result.push({
            json: {
                ...acc,
                action: "comment",
                wait_minutes: 5,
                scheduled_hour: currentHour
            }
        });

    }

}

// prevent empty output
if (result.length === 0) {
    return [{
        json: {
            action: "none",
            wait_minutes: 5
        }
    }];
}

return result;

// 1️⃣ Get httpbin single IP
const extractedIP = $input.first().json.origin
const myItems = $('Extract Account Fields').all();
const time=$('Loop Through Accounts').first().json.wait_minutes
// 3️⃣ Check if ANY matches
const isMatch = myItems.some(item => 
  item.json.last_allocated_ip.trim() === extractedIP || item.json.last_allocated_ip.trim()==extractedIP
);



// 4️⃣ Return ONLY ONE item
return [
  {
    json: {
      httpbin_ip: extractedIP,
      wait_minutes:time,
      ip_match: isMatch
    }
  }
];
